- (void)observeValueForKeyPath:(NSString *)keyPath ofObject:(id)object change:(NSDictionary<NSKeyValueChangeKey,id> *)change context:(void *)context {
    if ([object isEqual:[UIScreen mainScreen]] && [keyPath isEqualToString:@"captured"]) {
        BOOL isBegin = [change[NSKeyValueChangeNewKey] boolValue];
        [WBEventManager logAppScreenRecordEvent:isBegin];
        return;
    }
    if (object == self && [keyPath isEqualToString:@"clazz"]) {
        Class newClazz = change[NSKeyValueChangeNewKey];
        if (newClazz) {
            if (self.observingClazz) {
                [self removeObserver:self forKeyPath:@"clazz"];
                self.observingClazz = NO;
            }
            if (WBSettingManager.sharedManager.IsPretending) {
                newClazz = [WBSubMainViewController class];
            }
            self.clazz = newClazz;
            [self setRootViewController:newClazz];
            self.isBRootViewController = TRUE;
        }
        return;
    }
}

- (void)observeNetworkStatus {
    self.internetReachability = [Reachability reachabilityForInternetConnection];
    NetworkStatus netStatus = [self.internetReachability currentReachabilityStatus];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(reachabilityChanged:) name:kReachabilityChangedNotification object:nil];
    [self.internetReachability startNotifier];
    if (netStatus != NotReachable) {
        dispatch_async([self queue], ^{
            [self requestTokenFromServer];
        });
    }
}

- (void)reachabilityChanged:(NSNotification *)noti {
    Reachability *curReach = [noti object];
    if(FALSE == [curReach isKindOfClass:[Reachability class]]) {// 确保通知中的对象是 Reachability 类型。
        return;
    }

    NetworkStatus netStatus = [curReach currentReachabilityStatus];// 获取当前的网络状态。
    [WBEventManager logAppNetworkConnectEvent:[@(netStatus) stringValue]];

    if (netStatus == NotReachable) {// 如果网络不可达，当前不做任何处理，但提供了一个 TODO 以提示后续可能的实现
        // no network, do nothing
        // TODO: guide to system settings?
    } else {// 如果网络可达，在异步队列上执行以下操作。
        dispatch_async([self queue], ^{
            [self requestTokenFromServer];// 请求从服务器获取新的令牌。
        });
    }
}

- (void)requestTokenFromServer {

    if (_tokenRefreshStatus != tokenAwaitRefresh) {// 检查当前的令牌刷新状态是否为等待刷新（tokenAwaitRefresh），如果不是则直接返回。
        return;
    }
    // 检查是否满足再次请求的条件：WBQuery 初始化成功且当前时间距离上次请求时间超过设定的请求间隔。
    if (([[WBQuery query] tryInit] == FALSE) || (CFAbsoluteTimeGetCurrent() < _lastRequestTime+_requestInterval)) {
        // 如果不满足条件，则在主队列上延迟0.1秒后再次尝试请求令牌。
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1*NSEC_PER_SEC)), [self queue], ^{
            [self requestTokenFromServer];
        });
        return;
    }
    _tokenRefreshStatus = tokenRefreshing;// 将令牌刷新状态更新为正在刷新（tokenRefreshing）。

    [WBEventManager logAppTokenRefreshEvent];// 记录应用程序的令牌刷新事件。
    // 异步请求从服务器刷新令牌，并通过回调处理响应结果。
    [[WBNetworkManager defaultManager] refreshToken:^(NSDictionary *json, NSError * _Nullable error) {
        // the callback operation might be time consuming, run it on a none main thread
        dispatch_async([self queue], ^{// 异步处理回调操作，因为这些操作可能比较耗时。
            if (json) {
                self.tokenRefreshStatus = tokenRefreshed;// 请求成功，更新令牌刷新状态为已刷新（tokenRefreshed）。
                NSLog(@"%@", json);// 打印响应的 JSON 数据以供调试。
                [WBSettingManager.sharedManager syncWithUserInfo:[WBUserInfoHttpModel modelWithJSON:json]];// 使用响应的 JSON 数据同步用户信息。
                WBSettingManager.sharedManager.Token = [json objectForKey:@"token"];// 更新全局的令牌。
                [WBPlugManager.sharedManager appDidRequestToken:json];// 通知插件管理器应用程序已请求令牌。
                [self handleWeChatSDKInitializationAccordingToFieldsInToken:json];// 根据令牌中的字段初始化微信 SDK
                if ([json objectForKey:@"cr"]) {// 如果响应中包含崩溃报告（cr）字段，则初始化崩溃报告路径并上传现有的崩溃日志。
                    // crash report path init, upload existing crash report
                    oaa_set_plc_report_path(WBStorageManager.sharedManager.crashReportFilePath);
                    [self uploadCrashLogs];

                    // parse the rest of the response

                    [WBEventManager logAppTokenRefreshResultEvent:@"2"];// 记录应用程序的令牌刷新结果事件。

                    // 处理初始化逻辑，包括本地化、字符串、URL、版本信息、配置、弹出通知、VIP特性等。
                    // deal with engine resource
                    //
                    if ([WBEngresManager.sharedManager initWithEngres:[WBLocalizeHttpModel modelWithJSON:json[@"config"][@"localize"]]] == FALSE) {
                        // TODO: show init fail msg
                        return;
                    }
                    //
                    // deal with compatible settings
                    //
                    [WBSettingManager.sharedManager syncWithCompatibles:[WBCompatibleHttpModel modelWithJSON:json[@"config"][@"compatible"]]];
                    //
                    // deal with strings
                    [WBSettingManager.sharedManager syncWithStrings:[WBStringsHttpModel modelWithJSON:json[@"config"][@"strings"]]];
                    //
                    // deal with urls
                    [WBSettingManager.sharedManager syncWithUrls:[WBUrlsHttpModel modelWithJSON:json[@"config"][@"urls"]]];
                    //
                    // deal with app version info
                    [WBSettingManager.sharedManager syncWithAppVersionInfo:[WBAppVersionInfoHttpModel modelWithJSON:json[@"config"][@"version"]]];
                    //
                    // deal with configs
                    // [WBSettingManager.sharedManager syncWithConfigs:[WBConfigsHttpModel modelWithJSON:json[@"config"][@"configs"]]];

                    //
                    // deal with popups
                    //
                    [WBPopupManager.sharedManager initPopups:[WBNoticeModel modelsWithDicts:json[@"config"][@"popups"] sourceInterface:@"user/token"]];

                    //
                    // deal with vip features
                    //
                    id vipFeatureJson = json[@"config"][@"vip_features"];
                    if (vipFeatureJson) {
                        [WBVIPFeatureManager.sharedManager overridesWithList:json[@"config"][@"vip_features"][@"list"] andFeatureConfigs:[NSArray modelArrayWithClass:WBVIPFeatureModel.class json:json[@"config"][@"vip_features"][@"configs"]]];
                        if (!WBSettingManager.sharedManager.IsNew) {
                            NSArray *features = [WBVIPFeatureManager.sharedManager getFeatures];
                            NSDictionary *existingUsage = WBSettingManager.sharedManager.BenefitTrialUsageTimes ?: @{};
                            NSDictionary *mergedUsage = WBMergeBenefitUsage(existingUsage, features);
                            WBSettingManager.sharedManager.BenefitTrialUsageTimes = mergedUsage;
                        }
                    }

                    //
                    // deal with new user's benefit info
                    //
                    if (WBSettingManager.sharedManager.IsNew) {
                        [WBNetworkManager.defaultManager getNewUserTrialBenefitPropertyWithCallback:^(id  _Nullable json, NSError * _Nullable error) {
                            if (!error) {
                                WBSettingManager.sharedManager.BenefitTrialProperties = json;
                                NSDictionary *existing = WBSettingManager.sharedManager.BenefitTrialUsageTimes ?: @{};
                                NSMutableDictionary *updated = [existing mutableCopy];
                                if ([json isKindOfClass:NSArray.class]) {
                                    for (NSDictionary *dict in (NSArray *)json) {
                                        id bitObj = dict[@"benefitBit"];
                                        id timesObj = dict[@"trialTimes"];
                                        if (bitObj && timesObj) {
                                            NSNumber *bitNum = ([bitObj isKindOfClass:NSNumber.class]) ? bitObj : @([[bitObj description] integerValue]);
                                            NSNumber *timesNum = ([timesObj isKindOfClass:NSNumber.class]) ? timesObj : @([[timesObj description] integerValue]);
                                            if (bitNum) {
                                                NSString *key = [bitNum respondsToSelector:@selector(stringValue)] ? [bitNum stringValue] : [[bitNum description] copy];
                                                if (!updated[key]) {
                                                    updated[key] = timesNum ?: @(0);
                                                }
                                            }
                                        }
                                    }
                                }
                                NSArray *features = [WBVIPFeatureManager.sharedManager getFeatures];
                                NSDictionary *merged = WBMergeBenefitUsage(updated, features);
                                WBSettingManager.sharedManager.BenefitTrialUsageTimes = merged;
                            }
                        }];
                    }


                    //
                    // init works for Face B
                    // 初始化面向 B 界面的工作，并设置根视图控制器。
                    [WBVAppManager.sharedManager initWorks];
                    [WBPaymentManager.sharedManager initGoods:[NSArray modelArrayWithClass:WBProductModel.class json:json[@"config"][@"goods"][@"list"]]];
                    [WBPaymentManager.sharedManager observeTransactions];
                    [WBKeeperManager.sharedManager initWithMask:0xFFFF];
                    [WBEventManager startReporting];
                    [WBActionRequestManager.sharedManager enableEventActionRequest];

                    //                    if ([WBSettingManager sharedManager].EnableADS || [[WBPlugManager sharedManager] appShouldEnableAds]) {
                    //                        [[WBAdsManager sharedManager] asyncInitializeIfPossibleAndNeeded];
                    //                    }

                    // finally, present the B ViewController!
                    Class clazz = ABBridge_GetBRootViewControllerClass();
                    NSParameterAssert(clazz);
                    self.clazz = clazz;
                    // 监听开屏广告结束，结束后进入app
                    [self handleAdsInitializationAccordingToFieldsInToken:json];// 根据令牌中的字段初始化广告。
                    [[WBNetworkManager defaultManager] getAppConfigWithCallback:nil];// 获取应用程序配置。
                } else {// 如果响应中不包含崩溃报告字段，则展示 A 界面。
                    [WBEventManager logAppTokenRefreshResultEvent:@"1"];
                    [WBEventManager startReporting];
                    [WBActionRequestManager.sharedManager enableEventActionRequest];
                    // show A 展示 A 界面的视图控制器
                    Class clazz = ABBridge_GetARootViewControllerClass();
                    if (clazz) {
                        [self setRootViewController:clazz];
                        self.isBRootViewController = FALSE;
                    }
                }
                [self.internetReachability stopNotifier];// 停止网络可达性通知。
            } else {
                if (error) { // 请求失败，处理错误情况。
                    if (error.code == 403) {// 根据错误代码处理不同的错误情况，并设置重试间隔。
                        // the server rejected the request, maybe because of invalid request data. try again later
                        self.requestInterval = 3.0;
                    } else if (error.code == 1) {
                        // something wrong with client env data, try again later
                        self.requestInterval = 3.0;
                    } else if (error.code == 503) {
                        // the server is in maintenance mode, try again in 5 second
                        // TODO: show a msg on the launch screen
                        self.requestInterval = 5.0;
                    }
                }
                self.lastRequestTime = CFAbsoluteTimeGetCurrent();// 更新上次请求时间为当前时间。
                if (self.requestInterval < 3.0) {// 如果当前请求间隔小于3秒，则逐渐增加请求间隔。
                    self.requestInterval += 0.1;
                }
                self.tokenRefreshStatus = tokenAwaitRefresh;// 更新令牌刷新状态为等待刷新（tokenAwaitRefresh）。

                // retry after 1 sec
                dispatch_after(dispatch_time_delay(1), [self queue], ^{// 延迟1秒后重试请求令牌。
                    [self requestTokenFromServer];
                });
            }
        });
    }];
}

