        trackId = [@(WBSettingManager.sharedManager.TrackId) stringValue];
    }
    // 构造App Store中应用详情页的URL。
    NSString * url = [NSString stringWithFormat:@"itms-apps://itunes.apple.com/WebObjects/MZStore.woa/wa/viewSoftware?id=%@",trackId];
    [UIApplication.sharedApplication openURL:[NSURL URLWithString:url] options:@{} completionHandler:nil];// 打开URL，展示App Store中应用的详情。
}

