- (BOOL)isNetworkConnected {
    if (_internetReachability) {// 如果存在网络连接检测器并且当前网络状态是可达的，则返回TRUE，表示设备已连接到网络。
        NetworkStatus netStatus = [_internetReachability currentReachabilityStatus];
        if (netStatus != NotReachable) {
            return TRUE;
        }
    }
    return FALSE;
}

- (void)performURLScheme:(NSURL *)url {// 获取URL的绝对字符串形式。
    NSString *urlStr = [url absoluteString];
    if ([urlStr containsString:@"alipay"] && [url.host isEqualToString:@"safepay"]) {// 检查URL是否是支付宝支付链接，并处理支付结果。
        [self callbackPayResult:url];
    } else if ([url.scheme isEqualToString:@"webox"]) {// 检查URL的scheme是否为"webox"，并执行路由。
        [[WBRouteManager sharedManager] performRoute:url sourceInterface:nil];
    } else if ([url.scheme isEqualToString:@"file"] && [urlStr hasSuffix:@".ips"]){// 检查URL的scheme是否为"file"，并且URL包含".ips"后缀，并上传日志文件。
        [self postLogFilesWithURL:url];
    }
}

///支付回调统一处理
-(void)callbackPayResult:(NSURL *)url{
    //支付宝支付
    [[AlipaySDK defaultService] processOrderWithPaymentResult:url standbyCallback:^(NSDictionary *resultDic) {
        NSLog(@"result = %@",resultDic);
        [WBPaymentManager.sharedManager onAlipayClientSyncResult:resultDic[@"result"] resultStatus:resultDic[@"resultStatus"]];
    }];
}

///上传logs
- (void)postLogFilesWithURL:(NSURL *)url {
    [[WBNetworkManager defaultManager] postLogsWithFileName:@"file" fileURL:url callback:^(id  _Nullable json, NSError * _Nullable error) {
        if(error){
            NSString *descriptionStr =  error.userInfo[@"NSLocalizedDescription"];
            [SVProgressHUD showErrorWithStatus:descriptionStr];
            NSLog(@"save error:%@", error.userInfo);
        }else{
            [SVProgressHUD showSuccessWithStatus:@"上传成功"];
            NSLog(@"打印出的json为%@",json);
        }
    }];
}


- (void)uploadCrashLogs {
    // upload crash logs获取崩溃日志文件的路径。
    NSString *crashReportFilePath = [WBStorageManager sharedManager].crashReportFilePath;
    if ([[NSFileManager defaultManager] fileExistsAtPath:crashReportFilePath]) {// 检查崩溃日志文件是否存在。
        NSURL *crashReportFileURL = [NSURL fileURLWithPath:crashReportFilePath];// 将崩溃日志文件的路径转换为NSURL对象。
        NSParameterAssert(crashReportFileURL);// 使用NSParameterAssert确保crashReportFileURL不为nil，因为下一步需要这个URL。
        // 使用WBNetworkManager的postLogsWithFileName:fileURL:callback:方法异步上传崩溃日志。
        [[WBNetworkManager defaultManager] postLogsWithFileName:@"crash" fileURL:crashReportFileURL callback:^(id  _Nullable json, NSError * _Nullable error) {// 使用NSParameterAssert确保json和error只有一个是非nil的，因为上传操作应该只返回一个结果。
            NSParameterAssert(json == nil ^ error == nil);
            if (!error) {// 如果上传成功且没有错误，则尝试删除崩溃日志文件。
                NSError *err = nil;
                // clear file content
                [NSFileManager.defaultManager removeItemAtPath:crashReportFilePath error:&err];// 从文件系统中删除崩溃日志文件。
                NSParameterAssert(!err);// 使用NSParameterAssert确保在删除文件时没有发生错误。
            }
        }];
    }
}

// 上传客户端本地的路由执行日志
- (void)uploadRouteLogs {
    NSString *routeReportFilePath = [WBStorageManager sharedManager].routeLogFilePath;
    if ([[NSFileManager defaultManager] fileExistsAtPath:routeReportFilePath]) {
        NSURL *routeReportFileURL = [NSURL fileURLWithPath:routeReportFilePath];
        NSParameterAssert(routeReportFileURL);
        [[WBNetworkManager defaultManager] postRouteLogsWithFileURL:routeReportFileURL callback:^(id  _Nullable json, NSError * _Nullable error) {
            if (error) {
                NSLog(@"路由日志上传失败：%@", error.localizedDescription);
            } else {
                // 成功上传后清理日志
                [NSFileManager.defaultManager removeItemAtPath:routeReportFilePath error:&error];
            }
        }];
    }
}

- (void)loadAppConfig {
    NSDictionary *config = [[WBStorageManager sharedManager] loadAppConfig];
    self.globalPassword = config[@"globalPassword"];
    if (!self.globalPassword || [self.globalPassword isEqualToString:@""]) {
        self.globalPassword = @"1234";
    }
}

- (void)saveAppConfig {
    NSDictionary *config = @{
        @"globalPassword": self.globalPassword ?: @"1234"
    };
    [[WBStorageManager sharedManager] saveAppConfig:config];
}

- (void)saveGlobalPassword:(NSString *)password {
    self.globalPassword = password;
    [self saveAppConfig];
}

- (void)modifyGlobalPasswordByServer:(NSString *)password msgId:(NSInteger)msgId {
    if (password && ![password isEqualToString:@""]) {
        [self saveGlobalPassword:password];
        NSDictionary *data = @{
            @"msgId": @(msgId)
        };
        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeUserModifyPassword data:data defaultHandler:nil];
        [SVProgressHUD showSuccessWithStatus:@"密码修改成功！"];
    } else {
        [SVProgressHUD showErrorWithStatus:@"密码有误"];
    }
}


#pragma mark - blur effect when enter background

- (UIVisualEffectView *)blurEffectView {
    if (!_blurEffectView) {
        UIBlurEffect *blurEffect = [UIBlurEffect effectWithStyle:UIBlurEffectStyleLight];
        _blurEffectView = [[UIVisualEffectView alloc] initWithEffect:blurEffect];
        UIWindow *window = [WBAppManager getUIApplicationKeywindow];
        _blurEffectView.frame = window.bounds;
        _blurEffectView.alpha = 0;
    }
    return _blurEffectView;
}

- (BOOL)isBlurEffectPresented {
    return _blurEffectView != nil && _blurEffectView.superview != nil;
}

- (void)presentBlurEffect {
    //only apply the blur if the user hasn't disabled transparency effects
    if (UIAccessibilityIsReduceTransparencyEnabled()) return;
    UIWindow *window = [WBAppManager getUIApplicationKeywindow];

    [window addSubview:self.blurEffectView]; //if you have more UIViews, use an insertSubview API to place it where needed
    [UIView animateWithDuration:0.3 animations:^{
        self.blurEffectView.alpha = 1.0;
    } completion:nil];
}

- (void)dismissBlurEffect {
    [UIView animateWithDuration:0.3 animations:^{
        self.blurEffectView.alpha = 0;
    } completion:^(BOOL finished) {
        [self.blurEffectView removeFromSuperview];
    }];
}


